import{_ as t,o as n,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt3801.jpg",o="/images/lekt3803.jpg",l="/images/lekt3806.jpg",s="/images/lekt3807.jpg",u="/images/lekt3808.jpg",d="/images/lekt3802.jpg",p="/images/lekt3805.jpg",m="/images/lekt3804.jpg",h="/images/lekt3809.jpg",c="/images/lekt3810.jpg",b="/images/lekt3811.jpg",k="/images/lekt3812.jpg",g="/images/lekt3813.jpg",f="/images/lekt3814.jpg",A=JSON.parse('{"title":"Lektion 38","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion38.md","filePath":"lektionen/lektion38.md"}'),q={name:"lektionen/lektion38.md"};function w(z,e,v,_,P,S){return n(),a("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-38" tabindex="-1">Lektion 38 <a class="header-anchor" href="#lektion-38" aria-label="Permalink to &quot;Lektion 38&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>38.1. Losung der Woche</li><li>38.2. Lautwandel von Nasalen im Wort</li><li>38.3. Deklination der Stämme auf -n <ul><li>38.3.1. Nomina auf -an sowie Nomina -man bzw. -van nach Vokal</li><li>38.3.2. Nomina auf -man bzw. -van nach Konsonant</li><li>38.3.3. Maskulina und Neutra auf -in, -min, -vin</li></ul></li><li>38.4. Zur Nominalbildung: तद्धित-Suffix -in</li><li>38.5. Syntaktisches zu नामन्</li><li>38.6. Syntaktisches zu आत्मन्</li><li>38.7. Konsonantisch auslautende Stämme als Vorderglieder von Komposita</li><li>38.8. Stämme auf -an als Hinterglied eines बहुव्रीहि</li><li>38.9. Wortliste</li><li>38.10. Übung</li><li>38.11. Wortliste zur Übersetzungsübung</li><li>38.12. Übersetzungsübung</li></ul><h2 id="_38-1-losung-der-woche" tabindex="-1">38.1. Losung der Woche <a class="header-anchor" href="#_38-1-losung-der-woche" aria-label="Permalink to &quot;38.1. Losung der Woche&quot;">​</a></h2><p>मनुस्मृति ४.३२ über rechtes Urinieren:</p><blockquote><p>प्रत्यग्नि प्रतिसूर्यं च<br> प्रतिसोमोदकद्विजम् ।<br> प्रतिगु प्रतिवातं च<br> प्रज्ञा नश्यति मेहतः ॥</p></blockquote><p>Erklärungen:</p><p>-अग्नि Neutrum Nom.Akk.sg. zu अग्नि m.</p><p>-गु Neutrum Nom.Akk.sg. zu गो m.f. &quot;Rind, Kuh&quot;</p><p><img src="'+i+'" alt=""><br> Abb.: ... प्रज्ञा नश्यति मेहतः<br> Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/105785814/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/105785814/</a>. -- Zugriff am 2008-12-31. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><h2 id="_38-2-lautwandel-von-nasalen-im-wort" tabindex="-1">38.2. Lautwandel von Nasalen im Wort <a class="header-anchor" href="#_38-2-lautwandel-von-nasalen-im-wort" aria-label="Permalink to &quot;38.2. Lautwandel von Nasalen im Wort&quot;">​</a></h2><p>Nasale im Wort werden darauffolgenden Konsonanten assimiliert, d. h. sie werden durch den diesen Konsonanten entsprechenden Nasal ersetzt.</p><p>Nach c- und j- wird -n- durch -ñ- ersetzt.</p><h2 id="_38-3-deklination-der-stamme-auf-n" tabindex="-1">38.3. Deklination der Stämme auf -n <a class="header-anchor" href="#_38-3-deklination-der-stamme-auf-n" aria-label="Permalink to &quot;38.3. Deklination der Stämme auf -n&quot;">​</a></h2><h3 id="_38-3-1-nomina-auf-an-sowie-nomina-man-bzw-van-nach-vokal" tabindex="-1">38.3.1. Nomina auf -an sowie Nomina -man bzw. -van nach Vokal <a class="header-anchor" href="#_38-3-1-nomina-auf-an-sowie-nomina-man-bzw-van-nach-vokal" aria-label="Permalink to &quot;38.3.1. Nomina auf -an sowie Nomina -man bzw. -van nach Vokal&quot;">​</a></h3><table><tbody><tr><td colspan="5">**Nomina auf -an sowie Nomina -man bzw. -van nach Vokal haben drei Stämme:<br> **</td></tr><tr><td>**Starker Stamm**</td><td>**-ān**</td><td>**-mān**</td><td>**-vān**</td><td>**Nom., Akk., Vok. sg. m. f.<br>Nom., Akk., Vok. dual m. f.<br>Nom., Vok. pl. m. f.<br>Nom., Akk. pl. n.<br> **</td></tr><tr><td>**Mittlerer Schwacher Stamm**</td><td>**-a<br>aus -*n**</td><td>**-ma<br>aus -*mn**</td><td>**-va<br>aus -*vn**</td><td>**Übrige Kasus vor konsonantisch anlautender Endung<br>Wahlweise auch Lok. sg. m. n. f.**</td></tr><tr><td>**Schwächster Stamm**</td><td>**-n**</td><td>**-mn**</td><td>**-vn**</td><td>**Übrige Kasus vor vokalisch anlautender Endung**</td></tr><tr><td colspan="5">**<br>Die Endungen sind regelmäßig.****Der Nominativ Singular m. f. wird ohne auslautendes -n gebildet-**</td></tr></tbody></table><p>Beispiele:</p><p>राजन् m. &quot;König&quot;</p><ul><li>starker Stamm: राजान्</li><li>mittlerer Stamm: राज</li><li>schwächster Stamm: राज्ञ्</li></ul><p>सीमन् f. &quot;Grenze&quot;</p><ul><li>starker Stamm: सीमान्</li><li>mittlerer Stamm: सीम</li><li>schwächster Stamm: सीम्न्</li></ul><p>नामन् n. &quot;Name&quot;</p><ul><li>starker Stamm: नामान्</li><li>mittlerer Stamm: नाम</li><li>schwächster Stamm: नाम्न्</li></ul><table tabindex="0"><thead><tr><th></th><th>राजन्</th><th>सीमन्</th><th>नामन्</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td></tr><tr><td>एकवचनम्</td><td></td><td></td><td></td></tr></tbody></table><p>|   |   |   | | प्रथमा | राजा | सीमा | नाम | | द्वितिया | राजानम् | सीमानम् | नाम | | तृतीया | राज्ञा | सीम्ना | नाम्ना | | चतुर्थी | राज्ञे | सीम्ने | नाम्ने | | पञ्चमी | राज्ञस् | सीम्नस् | नाम्नस् | | षष्ठी | राज्ञस् | सीम्नस् | नाम्नस् | | सप्तमी | राज्ञि<br> राजनि | सीम्नि<br> सीमनि | नाम्नि<br> नामनि | |   |   |   |   | |</p><p>बहुवचनम्</p><p>|   |   |   | | प्रथमा | राजानस् | सीमानस् | नामानि | | द्वितीया | राज्ञस् | सीम्नस् | नामानि | | तृतीया | राजभिस् | सीम्नभिस् | नामभिस् | | चतुर्थी | राजभ्यस् | सीम्नभ्यस् | नामभ्यस् | | पञ्चमी | राजभ्यस् | सीम्नभ्यस् | नामभ्यस् | | षष्ठी | राज्ञाम् | सीम्नाम् | नाम्नाम् | | सप्तमी | राजसु | सीमसु | नामसु |</p><p><img src="'+o+'" alt=""><br> Abb.: सीमा<br> Grenzübergang zwischen Indien und Pakistan in Wagah (वाघा / واہگہ / ਵਾਘਾ)<br> [Bildquelle: Vandelizer. -- <a href="http://www.flickr.com/photos/jeremy_vandel/99163975/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jeremy_vandel/99163975/</a>. -- Zugriff am 2008-12-31. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h3 id="_38-3-2-nomina-auf-man-bzw-van-nach-konsonant" tabindex="-1">38.3.2. Nomina auf -man bzw. -van nach Konsonant <a class="header-anchor" href="#_38-3-2-nomina-auf-man-bzw-van-nach-konsonant" aria-label="Permalink to &quot;38.3.2. Nomina auf -man bzw. -van nach Konsonant&quot;">​</a></h3><ul><li>Starker Stamm: -mān, -vān</li><li>Schwacher Stamm: <ul><li>vor konsonantisch anlautenden Endungen: -ma, -va (aus -*mn, -*vn)</li><li>vor vokalisch anlautenden Endungen: -man, -van</li></ul></li></ul><p>Sonst Bildung wie unter 3.1.</p><p>Beispiele:</p><p>आत्मन् n. &quot;Seele&quot;</p><ul><li>starker Stamm: आत्मान्</li><li>schwacher Stamm: <ul><li>vor Konsonant: आत्म</li><li>vor Vokal: आत्मन्</li></ul></li></ul><p>ब्रह्मन् n.: Absolutes, Veda, Brahman</p><ul><li>starker Stamm: ब्रह्मान्</li><li>schwacher Stamm: <ul><li>vor Konsonant: ब्रह्म</li><li>vor Vokal: ब्रह्मन्</li></ul></li></ul><table tabindex="0"><thead><tr><th></th><th>आत्मन्</th><th>ब्रह्मन्</th></tr></thead><tbody><tr><td></td><td></td><td></td></tr><tr><td>एकवचनम्</td><td></td><td></td></tr></tbody></table><p>|   |   | | प्रथमा | आत्मा | ब्रह्म | | द्वितिया | आत्मानम् | ब्रह्म | | तृतीया | आत्मना | ब्रह्मणा | | चतुर्थी | आत्मने | ब्रह्मण्E | | पञ्चमी | आत्मनस् | ब्रह्मणस् | | षष्ठी | आत्मनस् | ब्रह्मणस् | | सप्तमी | आत्मनि | ब्रह्मणि | |   |   |   | |</p><p>बहुवचनम्</p><p>|   |   | | प्रथमा | आत्मानस् | ब्रह्माणि | | द्वितीया | आत्मनस् | ब्रह्माणी | | तृतीया | आत्मभिस् | ब्रह्मभिस् | | चतुर्थी | आत्मभ्यस् | ब्रह्मभ्यस् | | पञ्चमी | आत्मभ्यस् | ब्रह्मभ्यस् | | षष्ठी | आत्मनाम् | ब्रह्मणाम् | | सप्तमी | आत्मसु | ब्रह्मसु |</p><h3 id="_38-3-3-maskulina-und-neutra-auf-in-min-vin" tabindex="-1">38.3.3. Maskulina und Neutra auf -in, -min, -vin <a class="header-anchor" href="#_38-3-3-maskulina-und-neutra-auf-in-min-vin" aria-label="Permalink to &quot;38.3.3. Maskulina und Neutra auf -in, -min, -vin&quot;">​</a></h3><p>Diese Nomina haben keine Stammabstufung.</p><p>Nom.sg.m. und Nom.Akk.pl.n. sind in Analogie zu den -an-Stämmen gebildet (Dehnung des -i-), ebenso der Stamm auf -i- vor konsonantischer Endung.</p><p>Das Femininum wird mit dem Suffix -ī gebildet: z.B. बलिनी</p><p>Beispiel:</p><p>बलिन् m.n. &quot;stark, kräftig (durch besonderes बल gekennzeichnet, बल besitzend)&quot;</p><table><tbody><tr><td></td><td>**पुंस्**</td><td>**नपुंसकम्**</td></tr><tr><td>**एकवचनम्**</td><td></td><td></td></tr><tr><td>**प्रथमा**</td><td>बली</td><td>बलि</td></tr><tr><td>**द्वितिया**</td><td>बलिनम्</td><td>बलि</td></tr><tr><td>**तृतीया**</td><td colspan="2">बलिना</td></tr><tr><td>**चतुर्थी**</td><td colspan="2">बलिने</td></tr><tr><td>**पञ्चमी**</td><td colspan="2">बलिनस्</td></tr><tr><td>**षष्ठी**</td><td colspan="2">बलिनस्</td></tr><tr><td>**सप्तमी**</td><td colspan="2">बलिनि</td></tr><tr><td></td><td></td><td></td></tr><tr><td>**बहुवचनम्**</td><td></td><td></td></tr><tr><td>**प्रथमा**</td><td>बलिनस्</td><td>बलीनि</td></tr><tr><td>**द्वितीया**</td><td>बलिनस्</td><td>बलीनि</td></tr><tr><td>**तृतीया**</td><td colspan="2">बलिभिस्</td></tr><tr><td>**चतुर्थी**</td><td colspan="2">बलिभ्यस्</td></tr><tr><td>**पञ्चमी**</td><td colspan="2">बलिभ्यस्</td></tr><tr><td>**षष्ठी**</td><td colspan="2">बलिनाम्</td></tr><tr><td>**सप्तमी**</td><td colspan="2">बलिषु</td></tr></tbody></table><h2 id="_38-4-zur-nominalbildung-तद्धित-suffix-in" tabindex="-1">38.4. Zur Nominalbildung: तद्धित-Suffix -in <a class="header-anchor" href="#_38-4-zur-nominalbildung-तद्धित-suffix-in" aria-label="Permalink to &quot;38.4. Zur Nominalbildung: तद्धित-Suffix -in&quot;">​</a></h2><p>Mit dem (sehr wichtigen!) तद्धित-Suffix -in werden aus Substantiven Adjektive gebildet in der Bedeutung:</p><p>gekennzeichnet durch, besitzend</p><p>Ursprünglich unterschied sich die Bildung mit dem Suffix -इन् von der mit -मन्त्/-वन्त् dadurch, dass -इन् die Kennzeichnung durch etas Besonderes bezeichnete, während -मन्त्/-वन्त् den Besitz von, die Kennzeichnung durch etwas ausdrückte, das gewöhnlich, allgemein ist.</p><p>Beispiel:</p><p>हस्तिन् m.: der durch eine besondere Hand gekennzeichnete = der Elefant (seine Hand ist ja keine gewöhnliche Hand, sondern ein Rüssel)</p><p><img src="'+l+'" alt=""><br> Abb.: हस्ती<br> Nagarhole National Park = ನಾಗರಹೊಳೆ ರಾಷ್ಟ್ರೀಯ ಉದ್ಯಾನವನ<br> [Bildquelle: gopalarathnam_v. -- <a href="http://www.flickr.com/photos/gopalarathnam_v/3040514203/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/gopalarathnam_v/3040514203/</a>. -- Zugriff am 2009-01-01. --  <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>हस्तवन्त् : einer, der (menschliche) Hände hat</p><p><img src="'+s+'" alt=""><br> Abb.: हस्तवान्<br> जयपुर<br> [Bildquelle: brewingluminous. -- <a href="http://www.flickr.com/photos/brewingluminous/958598614/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/brewingluminous/958598614/</a>. -- Zugriff am 2009-01-01. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Adjektive auf -इन् werden gerne zu Komposita gebildet.</p><p>Beispiel:</p><p>सत्यवादिन् zu सत्यवाद m. &quot;Sprechen der Wahrheit&quot;: &quot;jemand, der durch Sprechen der Wahrheit gekennzeichnet ist = einer, der immer die Wahrheit spricht&quot;</p><h2 id="_38-5-syntaktisches-zu-नामन्" tabindex="-1">38.5. Syntaktisches zu नामन् <a class="header-anchor" href="#_38-5-syntaktisches-zu-नामन्" aria-label="Permalink to &quot;38.5. Syntaktisches zu नामन्&quot;">​</a></h2><p>Um auszudrücken &quot;jemand namens N. N.&quot;, konstruiert man:</p><p>N.N. (im Nominativ) नाम</p><p>Wörtlich: &quot;der Name ist/war N.N&quot;. Es handelt sich also um einen zwischengeschobenen Nominalsatz.</p><p>Beispiel:</p><blockquote><p>आसीद्राजा नलो नाम वीरसेनसुतो बली । &quot;Es war einmal ein König namens Nala, der starke Sohn Vīrasenas.&quot;</p></blockquote><p>Selbstverständlich kann man dasselbe mit einem बहुव्रीहि ausdrücken:</p><blockquote><p>देवदत्तनामा पुरुषः &quot;ein Mann, dessen Name Devadatta ist&quot;</p><p>मदयन्तिकानाम्नी बाला &quot;ein Mädchen, dessen Name Madayantika ist&quot;</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: आसीन्महात्मा गन्धी नाम<br> 1930er Jahre<br> [Bildquelle: Wikipedia. Public domain]</p><h2 id="_38-6-syntaktisches-zu-आत्मन्" tabindex="-1">38.6. Syntaktisches zu आत्मन् <a class="header-anchor" href="#_38-6-syntaktisches-zu-आत्मन्" aria-label="Permalink to &quot;38.6. Syntaktisches zu आत्मन्&quot;">​</a></h2><p>आत्मन् maskulinum kann im Singular als rückbezügliches Fürwort (Reflexivpronomen) für alle drei Geschlechter, Zahlen (auch Dual und Plural) und Personen gebraucht werden.</p><p>Beispiele:</p><blockquote><p>आत्मन्येषा दोषं न पश्यति । &quot;Sie sieht keinen Fehler an ihr selbst&quot;</p><p>आत्मानं स्तुवन्ति । &quot;Sie rühmen sich selbst&quot;</p></blockquote><p>Der Genetiv (षष्ठी) आत्मनस् kann deswegen stehen für &quot;mein/dein/sein/... eigenes&quot;</p><p>Beispiel:</p><blockquote><p>आत्मनो गृहं प्रविशति । &quot;Er betritt sein eigenes Haus.&quot;</p></blockquote><h2 id="_38-7-konsonantisch-auslautende-stamme-als-vorderglieder-von-komposita" tabindex="-1">38.7. Konsonantisch auslautende Stämme als Vorderglieder von Komposita <a class="header-anchor" href="#_38-7-konsonantisch-auslautende-stamme-als-vorderglieder-von-komposita" aria-label="Permalink to &quot;38.7. Konsonantisch auslautende Stämme als Vorderglieder von Komposita&quot;">​</a></h2><p>Stämme, die auf einen Konsonanten enden, erscheinen als Vorderglied eines Kompositums in dem (schachen) Stamm, den sie vor der Endung -su des Lokativ (सप्तमी) Plural annehmen.</p><p>Beispiel:</p><blockquote><p>राजपुत्र &quot;Königssohn&quot;</p></blockquote><h2 id="_38-8-stamme-auf-an-als-hinterglied-eines-बहुव्रीहि" tabindex="-1">38.8. Stämme auf -an als Hinterglied eines बहुव्रीहि <a class="header-anchor" href="#_38-8-stamme-auf-an-als-hinterglied-eines-बहुव्रीहि" aria-label="Permalink to &quot;38.8. Stämme auf -an als Hinterglied eines बहुव्रीहि&quot;">​</a></h2><p>Als Hinterglied eines बहुव्रीहि kann ein -an-Stamm für alle drei Geschlechter verwendet werden. In der Regel wird aber das Femininum mit dem Suffix -ī vom schwächsten Maskulinstamm gebildet.</p><p>Beispiel:</p><blockquote><p>दुर्णाम्नी &quot;eine, deren Name böse ist ; Krankheitsdämonin&quot;</p></blockquote><h2 id="_38-9-wortliste" tabindex="-1">38.9. Wortliste <a class="header-anchor" href="#_38-9-wortliste" aria-label="Permalink to &quot;38.9. Wortliste&quot;">​</a></h2><p>सूर्य m.: Sonne, Sonnengott Sūrya</p><p><img src="'+d+'" alt=""><br> Abb.: सूर्यः<br> सूर्य मंदिर, Konark = कोनार्क<br> [Bildquelle: PriyadarshiC. -- <a href="http://www.flickr.com/photos/2kool/421985480/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/2kool/421985480/</a>. -- Zugriff am 2008-12-31.  -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>उदक n.: Wasser</p><p><img src="'+p+'" alt=""><br> Abb.: उदकम्<br> Darewadi village, Ahmed Nagar District = अहमदनगर, महाराष्ट्र<br> [Bildquelle: Robin Murphy, World Resources Institute. -- <a href="http://www.flickr.com/photos/worldresourcesinstitute/2555779241/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldresourcesinstitute/2555779241/</a>. -- Zugriff am 2009-01-01. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>वा 2P वाति : wehen, blasen</p><blockquote><p>Fut. वास्यति<br> Perf. IV ववौ<br> Pass. वायते<br> Kaus. वापयति<br> PPP वान । वात<br> Inf. वातुम्</p><p>davon:</p><p>वात m.: Wind</p></blockquote><p>वा + निस् 2P निर्वाति : wehen, verwehen, erlöschen</p><blockquote><p>davon:</p><p>निर्वाण n.: Erlöschen, Nirvana</p><p>परिनिर्वाण n.: vollkommenes Erlöschen, vollkommene Erlösung (am Lebensende eines Buddha oder Arhant)</p></blockquote><p><img src="'+m+'" alt=""><br> Abb.: गौतमबुद्धस्य महापरिनिर्वाणम्<br> Gandhara, 2./3. Jhdt. n. Chr.<br> [Bildquelle: Wikipedia. Public domain]</p><p>मिह् 1P मेहति : pinkeln, pissen, ejakulieren</p><blockquote><p>Fut. मेक्ष्यति<br> Perf. II मिमेह, मिमिहुर्<br> Pass. मिह्यते<br> Kaus. मेहयति<br> PPP मीढ</p><p>davon:</p><p>मेघ m.: Wolke (&quot;Seicher&quot;)</p></blockquote><p>सुत m.: Sohn</p><p>राजन् m.: König (über das Königtum in Indien siehe Basham, Wonder S. 82 -94). Als Schlussglied eines Kompositums (bes. तत्पुरुष) meist: -राज m. (wie देव)</p><blockquote><p>Feminimum:</p><p>राज्ञी f.: Königin, Frau eines Königs</p><p>von राज :</p><p>राज्य 3: königlich; n. Königreich, Königtum, Herrschaft</p></blockquote><p>नामन् n.: Name</p><p>सीमन् f.: Grenze</p><p>आत्मन् m.: Selbst, eigene Person, innerstes Wesen. Philosophisch und in Erlösungslehren: das Absolute im Individuum, dessen sich aber das Individuum unter Umständen nicht bewusst ist (v. Stietencron)</p><p>ब्रह्मन् n.: das Absolute, der Veda (laut Thieme ursprünglich: die formulierte Wahrheit, davon ब्राह्मण &quot;Wahrheitsformulierer&quot;)</p><p>ब्रह्मन् m.: der persönlich gedachte Schöpfergott Brahmā</p><p><img src="'+h+'" alt=""><br> Abb.: ब्रह्मा<br> Halebidu = ಹಳೆಬೀಡು<br> [Bildquelle: Wikipedia. GNU FDLicense]</p><p>कर्मन् n.: zu कृ 8U: Handlung, Tat, Werk; heiliges Werk, Opferhandlung; Karma: das frühere Tun, das später seine Früchte bringt (z.B. in Wiedergeburt)</p><blockquote><p>कर्मविपाक m.: Reifen der Taten = die guten und bösen Konsequenzen von Taten in früheren Existenzen (zu वि-पच्)</p></blockquote><p>हस्तिन् m.: Elefant (<em>Elephas maximus</em>)</p><p>मनु m.: Mensch, Mann; Name des Vaters des menschengeschlechts (zu मन् 4Ā)</p><blockquote><p>davon:</p><p>मनुष्य m.: Mensch</p></blockquote><p>शुच् 1P शोचति : (flammen, leuchten) ; trauern, betrauern</p><blockquote><p>Perf II शुशोच, शुशुचुर्<br> Fut. शोचिष्यति<br> Pass. शुच्यते<br> Kaus. शोचयति<br> Inf. शुचितुम्<br> Absol. शोचित्वा । शुचित्वा</p><p>davon:</p><p>शुचि 3: leuchtend, rein, klar</p><p>शोक m.: Trauer, Gram</p><p>अशोक 3: frei von Gram; Ashoka-Baum = <em>Saraca asoca</em> (Roxb.) Wilde; Name des Kaisers Aśoka (देवानांप्रिय प्रियदर्शी) (ca. 304   232 v.Chr.)</p></blockquote><p><img src="'+c+'" alt=""><br> Abb.: Ashoka-Baum = <em>Saraca asoca</em> (Roxb.) Wilde<br> Kolkata = কলকাতা <br> [Bildquelle: J.M.Garg / Wikipedia. GNU FDLicense]</p><p><img src="'+b+'" alt=""><br> Abb.: Größte Ausdehnung des Reiches Aśokas sowie Fundorte seiner Felsen- und Säulenedikte<br> [Bildquelle: Wikipedia.GNU FDLicense]</p><h2 id="_38-10-ubung" tabindex="-1">38.10. Übung <a class="header-anchor" href="#_38-10-ubung" aria-label="Permalink to &quot;38.10. Übung&quot;">​</a></h2><p>A) Setzen Sie in folgenden Sätzen die entsprechende Form der Wörter in Klammern ein und übersetzen Sie:</p><p>... (सप्तमी विभक्तिः) ... धर्मं रक्षत्यभया जनाः ॥१॥ (राजन्)</p><p>आसीद्राजपुत्रो गौतमस् ... सुकृतकर्मोप्पन्नो बुध्या रूप्यमितबलः ॥२॥ (नामन्)</p><p>राज्यस्य ... (सप्तमी बहुवचने) ... अरयो राजानं योद्धुं तिष्ठन्ति ॥३॥ (सीमन्)</p><p>वैश्यानां कानि ... ॥४॥ (नामन्)</p><p>वैश्यास् ... ॥५॥ (किंनामन्)</p><p>... (सप्तम्येकवचने) ... अकर्म यः पश्येदकर्मणि च कर्म यः स बुद्धिमान्मनुष्येषु स युक्त इति भगवद्गीतायाम् ॥६॥ (कर्मन्)</p><p>किम् ... किमकर्मेति कवयो ऽप्यत्र मोहिताः ॥७॥ (कर्मन्)</p><p>ब्रह्मभूतस् ... (प्रथमैकवचने) ... न शोचति न लुभ्यति ॥८॥ (प्रसन्नात्मन्)</p><p>... (षष्ठ्येकवचने) ... सुकृतस्य सुफलमाहुः ॥९॥ (कर्मन्)</p><p>महीभोगस् ... (शष्ठी बहुवचने) ... धर्मः ॥१०॥ (राजन्)</p><p>रज्ञे ... दीयेरन् ॥११॥ (बलिन् हस्तिन्)</p><p>... (तृतीया विभक्तिः) ... लोका असृज्यन्त ॥१२॥ (ब्रह्मन् m.)</p><p>... (तृतीया विभक्तिः) ... कृतं पापं... (तृतीया विभक्तिः) ... अकृतं पापम् ॥१३॥ (आत्मन्)</p><p>सद्भिस् ... जनेभ्यो ऽभयं दीयते ॥१४॥ (राजन्)</p><p>... धर्मं न रक्षत्सु सभया जनाः ॥१५॥ (राजन्)</p><h2 id="_38-11-wortliste-zur-ubersetzungsubung" tabindex="-1">38.11. Wortliste zur Übersetzungsübung <a class="header-anchor" href="#_38-11-wortliste-zur-ubersetzungsubung" aria-label="Permalink to &quot;38.11. Wortliste zur Übersetzungsübung&quot;">​</a></h2><p>प्राय  m.: Hauptsache, Instr. प्रायेण : meist, gewöhnlich (zu प्र-इ)</p><p>विनोद m.: Zeitvertreib, Unterhaltung, Vergnügen</p><p><img src="'+k+'" alt=""><br> Abb.: विनोदः<br> Carrom-Spiel<br> [Bildquelle: nicolas - نِيقُولاَوُسَ . -- <a href="http://www.flickr.com/photos/keep-on-moving/3007779918/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/keep-on-moving/3007779918/</a>. -- Zugriff am 2009-01-01. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>अट् 1P अटति : herumschweifen</p><blockquote><p>Perf. I आट, आटुः<br> Fut. अटिष्यति<br> Kaus. आटयति</p></blockquote><p>गाध 3: seicht</p><p>तॄ 1P तरति : überqueren, sich retten vor (Akk.)</p><blockquote><p>Perf. IIIb ततार, तेरुः<br> Fut. तरिष्यति । तरीष्यति<br> Pass. तीर्यते<br> Kaus. टारयति<br> PPP तीर्ण<br> Inf. तरितुम् । तरीतुम्</p></blockquote><p>पार n.(m.): jenseitiges Ufer, Grenze, Ziel</p><p>तीर n.: Ufer</p><p><img src="'+g+'" alt=""><br> Abb.: वाराणस्यां गङ्गातीरे<br> [Bildquelle: nassio. -- <a href="http://www.flickr.com/photos/26116629@N04/2450959377/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/26116629@N04/2450959377/</a>. -- Zugriff am 2009-01-01. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>एकैकशस् Adv.: je einzeln</p><p>गण् 10P गणयति : zählen</p><blockquote><p>Perf. गणयां चकार<br> Fut. गणयिष्यति<br> Pass. गण्यते<br> PPP गणित<br> Absol. -गणय्य<br> Inf. गणयितुम्</p></blockquote><p><img src="'+f+'" alt=""><br> Abb.: गणयां चक्रुः<br> करणी माता मंदिर, देशनोके<br> [Bildquelle: neilhinchley. -- <a href="http://www.flickr.com/photos/neilhinchley/50518886/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/neilhinchley/50518886/</a>. -- Zugriff am 2009-01-01. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>क्रुश् 1P क्रोशति : schreien, wehklagen</p><blockquote><p>Perf. II चुक्रोश<br> Fut. क्रोक्ष्यति<br> Pass. क्रुश्यते<br> Kaus. क्रोशयति<br> PPP क्रुष्ट</p></blockquote><p>इदानीम् Adv.: jetzt</p><p>नूनम् Adv.: jetzt; also, darum; gewiss, sicherlich</p><p>मज्ज् 6P मज्जति : sinken, tauchen</p><blockquote><p>PPP ममज्ज<br> Fut. मङ्क्ष्यति<br> Kaus. मज्जयति<br> PPP मग्न<br> Absol. मङ्क्त्वा । मक्त्वा</p></blockquote><p>गवेषयति Denominativ: suchen</p><p>व्याकुल 3: bestürzt, aufgeregt, verwirrt</p><p>कोलाहल m.n.: Geschrei, Lärm</p><p>विवेष्टित n.: das Rundherum-Suchen</p><p>हस् 1P हसति : lachen</p><blockquote><p>Perf. Vc जहास, जहसुर्<br> Fut. हसिष्यति<br> Pass. हस्यते<br> Kaus. हासयति<br> PPP हसित</p></blockquote><p>सृ 1P सरति : laufen</p><blockquote><p>Perf. ससार, सस्रुर्<br> Fut. सरिष्यति<br> Pass. स्रियते<br> Kaus. सारयति<br> PPP सृत<br> Inf. सर्तुम्</p></blockquote><p>कर्णयति Denominativ: hören (zu कर्ण m. &quot;Ohr&quot;)</p><p>लज्जा f.: Scham</p><p>अधस् Adv.: nach unten</p><h2 id="_38-12-ubersetzungsubung" tabindex="-1">38.12. Übersetzungsübung <a class="header-anchor" href="#_38-12-ubersetzungsubung" aria-label="Permalink to &quot;38.12. Übersetzungsübung&quot;">​</a></h2><p>दश मूढाः</p><p>मूढानां चेष्टितानि प्रायेण विनोदावहानि । यथा हि -- एकदा दश मूढा देशाटनाय प्रस्थिताः । किञ्चिद्दूरं गतानां तेषामुपस्थिता काचिदगाधा नदी । बाहुभ्यां तरन्तस्ते कथमपि नदीं तीर्त्वा पारं गताः ॥</p><p>आसीत्तेषां मध्ये कश्चन वृद्धः । स किं सर्वे तीरमनुप्राप्ता ईति जिज्ञासमानस्तानेकैकशो गणयामास । परं नवैव परिगणितास्तेन । ततः स आक्रोशत् । अहो वयम् दश प्रस्थिताः । इदानीं नवैव स्मः । नूनमस्माकमेको नद्यां निमग्नः । गवेषयत तमिति । ततस्तेषामेकैको ऽपि गणनां चकार । परं नवैव दृश्यन्ते । ततस्तेषां व्याकुलीभूतानां महान्कोलाहलः समजनि । तत्रैव नातिदूरे कस्यचिदृषेराश्रमो ऽवर्तत । तत्र वसन्नृषिस्तेषां विवेष्टितमवलोक्योच्चैर्जहास । तस्य हासशब्दं श्रुत्वा मूढास्तरसा समुपसृत्य हासकारणमपृच्छन् । ऋषिराह । अहो । अनात्मज्ञा यूयम् । युष्माकमेकैको ऽपि नात्मानमगणयत् । तेनायं व्यामोहः संजात इति । तदाकर्ण्य ते मूढाः सलज्जमधोमुखाः प्रययुः ॥ (संस्कृतप्रथमादर्शः)</p><p>Erklärungen:</p><p>दश Nom.Akk.pl.m.f.n. zu दशन् &quot;zehn&quot;</p><p>बाहुभ्याम् Instr.Dat.Abl. Dual zu बाहु m. &quot;Arm&quot;</p><p>सर्वे Nom.pl.m. zu सर्व 3 &quot;jeder, alle&quot;</p><p>जिज्ञासमान Part.Präs.Ā.Desiderativ zu ज्ञा 9U जिज्ञासते &quot;erkennen wollen, wissen wollen&quot;</p><p>नव Nom.Akk.pl.m.f.n. zu नवन् &quot;neun&quot;</p><p>ययम् Nom.pl. &quot;wir&quot;</p><p>स्मस् 1.pl.Ind.Präs.P zu अस् 2P</p><p>गवेषयत 2.pl.Imperativ P</p><p>एकैक &quot;jeder einzeln&quot;</p><p>समजनि 3.sg.Passiv Aorist zu जन्</p><p>तरसा Instr. sg. zu तरस् n. &quot;Energie&quot;, adverbial gebraucht: &quot;rasch, mit Gewalt&quot;</p><p>यूयम् Nom.pl. &quot;ihr&quot;</p><p>युष्माकम् Gen.pl. zu यूयम्</p>',182)])])}const K=t(q,[["render",w]]);export{A as __pageData,K as default};
